export const EXAM_5: Exam = {
  title: "Mock Exam 5",
  subtitle: "Full-Length Simulation E — Multinational & Generative AI",
  sections: [
    // SCENARIO 1 – Multi-national integrated management system (D1/D3/D4 mix)
    { type: "scenario", scenario: "OmniCorp is a multinational conglomerate headquartered in Germany with subsidiaries in Japan, Brazil, and Canada. The group holds ISO 9001 and ISO/IEC 27001 certifications. The board has mandated ISO/IEC 42001 certification for the parent company and its Brazilian subsidiary, which develops generative AI content-moderation tools sold to social-media platforms worldwide. The Japanese subsidiary uses AI only for internal predictive maintenance, while the Canadian subsidiary resells third-party AI analytics. OmniCorp's group CISO proposes a single, consolidated AIMS covering all four entities. The Brazilian subsidiary's AI team has been operating under its own informal AI governance charter for two years.", questions: [
      { question: "The group CISO proposes one consolidated AIMS for all four entities. What is the most significant challenge the organization must address when defining scope under Clause 4.3?", options: ["Determining whether a single Statement of Applicability can reference different Annex A controls for each subsidiary based on their distinct AI activities, risk profiles, and regulatory contexts", "Ensuring the Japanese subsidiary's predictive maintenance system uses the same AI model architecture as the Brazilian subsidiary for consistency", "Selecting a single certification body that holds accreditation in all four countries before scope can be finalized"], correct: 0, explanation: "Clause 4.3 requires considering internal and external issues and interested-party requirements. Different subsidiaries have different AI activities, risk levels, and regulatory environments, making a uniform SoA impractical without careful tailoring." },
      { question: "The Brazilian subsidiary has operated under an informal AI governance charter for two years. How should this be treated during AIMS implementation?", options: ["Discard the charter entirely since it was not developed under ISO/IEC 42001 and could introduce non-conforming practices", "Conduct a gap analysis mapping the charter's existing controls to ISO/IEC 42001 requirements, retaining effective practices and formalizing them within the AIMS", "Adopt the charter as-is as the organization's AI policy, since two years of operation demonstrates adequacy"], correct: 1, explanation: "Best practice is to build on existing effective controls rather than starting from scratch. A gap analysis identifies what can be retained and what needs enhancement to conform with ISO/IEC 42001." },
      { question: "The Canadian subsidiary resells third-party AI analytics without developing or modifying the AI. Must it be included in the AIMS scope?", options: ["No, resellers are not providers or users of AI systems and fall outside the scope of ISO/IEC 42001", "Yes, organizations that use or provide products or services utilizing AI systems are within scope, regardless of whether they developed the AI", "Only if the third-party vendor does not hold its own ISO/IEC 42001 certification"], correct: 1, explanation: "ISO/IEC 42001 Clause 1 applies to organizations that provide or use products or services utilizing AI systems. Reselling AI analytics means the Canadian subsidiary provides AI-based services and must manage associated risks." },
      { question: "OmniCorp must comply with the EU AI Act for its German operations, Brazil's LGPD for data protection, and Japan's AI governance guidelines. How should these be incorporated into the AIMS?", options: ["Create three separate compliance programs outside the AIMS, each managed by the respective subsidiary's legal department", "Address each jurisdiction's requirements as external issues under Clause 4.1 and interested-party requirements under Clause 4.2, integrating them into a unified risk assessment and control framework", "Apply only the most stringent jurisdiction's requirements uniformly across all entities to simplify compliance"], correct: 1, explanation: "Clause 4.1 and 4.2 require identifying external issues and interested-party requirements. Multi-jurisdictional requirements should be mapped and integrated into the AIMS rather than managed in silos or applied uniformly." },
      { question: "OmniCorp already holds ISO 9001 and ISO/IEC 27001. The implementation team proposes reusing the existing internal audit program without modification. What is the most appropriate response?", options: ["Reuse the existing audit program structure but extend its scope to cover AI-specific requirements, ensure auditors have AI competence, and add AI-related audit criteria from ISO/IEC 42001 Clause 9.2", "This is fully appropriate since all three standards share the Harmonized Structure and have identical audit requirements", "Create a completely separate internal audit program for the AIMS to avoid contaminating the existing programs"], correct: 0, explanation: "While the Harmonized Structure enables integration, ISO/IEC 42001 introduces AI-specific requirements that must be reflected in audit criteria. Auditors also need AI-specific competence. The program should be extended, not duplicated or reused without modification." }
    ]},

    // SCENARIO 2 – Generative AI content moderation challenges (D4/D1/D3)
    { type: "scenario", scenario: "StreamSafe develops a generative AI system that automatically moderates user-generated content on social media platforms. The system processes text, images, and video in twelve languages. During operational testing, the team discovers that the model disproportionately flags content from certain cultural contexts as harmful when it is actually benign cultural expression. The data governance lead reveals that 78% of the training data originated from English-language sources. A major client demands real-time explainability for every moderation decision. The product team has been deploying weekly model updates directly to production without formal change control.", questions: [
      { question: "The model disproportionately flags benign cultural expressions from certain contexts. Which Annex A control area is most directly relevant to addressing this issue?", options: ["Controls related to AI system impact assessment, requiring evaluation of how AI outputs affect different populations and communities", "Controls related to documented information management, ensuring all moderation decisions are logged", "Controls related to communication with interested parties, requiring disclosure of the moderation criteria to platform users"], correct: 0, explanation: "AI system impact assessment controls (Annex A) require evaluating effects on individuals and groups. Cultural bias in moderation directly impacts affected communities and must be assessed as part of the AI system's societal impact." },
      { question: "The training data is 78% English-language. Under ISO/IEC 42001's data governance requirements, what must the organization do?", options: ["Document the data distribution in the system's technical specification and accept the limitation as inherent to available data", "Assess data representativeness as part of data quality management, document the identified gap, treat the associated bias risk, and establish controls for ongoing data quality monitoring", "Supplement the English data with machine-translated versions to achieve equal language distribution"], correct: 1, explanation: "Data governance controls require assessing data quality including representativeness. A known imbalance must be treated as a risk, not merely documented or addressed through potentially unreliable machine translation." },
      { question: "The client demands real-time explainability for every moderation decision. How should this requirement be addressed within the AIMS framework?", options: ["Reject the requirement as technically infeasible for generative AI models operating at scale", "Assess the requirement against the organization's AI policy, determine the appropriate level of explainability as part of risk treatment, document the agreed approach in the client contract, and implement corresponding Annex A transparency controls", "Implement a simple rule-based override system that provides explanations, replacing the AI model for moderation decisions that require justification"], correct: 1, explanation: "Explainability requirements should be evaluated through the AIMS framework, balanced against technical feasibility, documented in agreements, and addressed through appropriate transparency controls rather than dismissed or bypassed." },
      { question: "Weekly model updates are deployed to production without formal change control. Which AIMS requirements does this violate?", options: ["Clause 8.1 operational planning and control, which requires established criteria for processes and implementation of control including management of changes to AI systems", "Clause 7.5 documented information only, since the updates themselves are documented in the version control system", "Clause 6.2 AI objectives, since model updates should be tied to specific measurable objectives"], correct: 0, explanation: "Clause 8.1 requires operational planning and control with established criteria, including management of changes. Deploying model updates without change control violates the requirement for controlled processes and change management." },
      { question: "A platform user files a complaint alleging the AI system censored legitimate political speech. Under which AIMS processes should this complaint be handled?", options: ["Only through the platform client's own complaint mechanism, as StreamSafe is a B2B provider with no direct relationship with end users", "Through the AIMS communication process (Clause 7.4) for handling external communications, feeding into the AI risk assessment (Clause 8.2) to evaluate whether the complaint indicates a systemic issue, and potentially triggering corrective action (Clause 10.1)", "Through the management review process (Clause 9.3) at the next scheduled review, as individual complaints do not warrant immediate action"], correct: 1, explanation: "Complaints from affected parties should be handled through communication processes, evaluated for systemic risk implications, and trigger corrective action if a nonconformity is identified. Waiting for management review is insufficient for timely response." }
    ]},

    // SCENARIO 3 – Complex supply chain with AI components (D4/D3)
    { type: "scenario", scenario: "AutoDrive manufactures autonomous vehicle components and uses AI systems sourced from multiple vendors. The perception system comes from Vendor A (a startup with no formal AI governance), the decision-planning module from Vendor B (ISO/IEC 42001 certified), and the natural language interface from Vendor C (a large tech company with proprietary governance). AutoDrive's AIMS team must manage these third-party AI components within their management system. During a recent incident, the perception system misclassified a road obstacle, and AutoDrive could not obtain sufficient technical information from Vendor A to conduct a root cause analysis. The safety officer has raised concerns that Vendor C's governance framework is opaque and may not meet ISO/IEC 42001 expectations.", questions: [
      { question: "AutoDrive cannot obtain technical information from Vendor A for root cause analysis after an incident. What AIMS control deficiency does this reveal?", options: ["A deficiency in Clause 9.1 monitoring, as AutoDrive should have detected the misclassification before the incident occurred", "A deficiency in third-party management controls: the organization should have established contractual requirements for transparency, incident cooperation, and access to technical information from AI suppliers", "A deficiency in Clause 5.1 leadership, as top management should have prevented the use of startup vendors for safety-critical components"], correct: 1, explanation: "Annex A controls on third-party and supply chain management require establishing contractual and governance requirements with AI suppliers, including provisions for incident investigation and access to necessary technical information." },
      { question: "Vendor B holds ISO/IEC 42001 certification. Does this eliminate AutoDrive's obligation to assess the decision-planning module's risks?", options: ["Yes, Vendor B's certification transfers all AI risk responsibility for that component to the vendor", "No, AutoDrive must still assess risks of the integrated system including how Vendor B's component interacts with other components, even though Vendor B's certification provides assurance about the vendor's own governance", "Only if AutoDrive's certification body accepts Vendor B's certificate as sufficient evidence"], correct: 1, explanation: "An organization using AI cannot transfer its own AIMS responsibility. Vendor certification provides assurance but does not eliminate the integrator's obligation to assess risks of the integrated system, including component interactions." },
      { question: "The safety officer is concerned that Vendor C's proprietary governance framework is opaque. What is the most appropriate AIMS-aligned action?", options: ["Accept Vendor C's governance as adequate since the company is large and well-resourced, reducing the likelihood of governance failures", "Define minimum governance requirements based on ISO/IEC 42001 and contractually require Vendor C to demonstrate compliance or provide equivalent assurance, conducting supplier assessments as needed", "Replace Vendor C with a vendor that holds ISO/IEC 42001 certification, as proprietary frameworks cannot be assessed against the standard"], correct: 1, explanation: "The organization should define its governance expectations and require vendors to demonstrate compliance through contractual terms and assessments, rather than assuming adequacy based on vendor size or requiring exact standard certification." },
      { question: "AutoDrive integrates AI components from three vendors into a single autonomous system. What AI lifecycle consideration is most critical for the AIMS?", options: ["Ensuring all vendors use the same machine learning framework to guarantee component compatibility", "Managing the interfaces between AI components throughout the system lifecycle, including integration testing, monitoring component interactions in production, and coordinating updates across vendors", "Assigning a single vendor as the system integrator to simplify lifecycle management"], correct: 1, explanation: "When multiple AI components are integrated, the interfaces and interactions between them create emergent risks that must be managed throughout the lifecycle. This requires coordinated testing, monitoring, and change management across all components." },
      { question: "After the perception system incident, AutoDrive's corrective action plan focuses solely on switching to a different perception vendor. Is this an adequate corrective action under Clause 10.1?", options: ["Yes, replacing the vendor that caused the incident removes the root cause", "No, Clause 10.1 requires analyzing the root cause of the nonconformity; switching vendors addresses the immediate issue but does not address potential systemic gaps in vendor assessment, integration testing, and third-party management processes", "Yes, provided the replacement vendor holds ISO/IEC 42001 certification"], correct: 1, explanation: "Clause 10.1 requires determining the cause of nonconformity and evaluating the need for action to ensure it does not recur. Simply switching vendors without addressing the systemic gaps in vendor management and integration testing does not prevent recurrence." }
    ]},

    // SCENARIO 4 – Leadership and organizational roles in a matrix organization (D3)
    { type: "scenario", scenario: "PharmaTech operates a matrix organization where AI projects report to both the R&D division and the Digital Transformation office. The CEO has endorsed the AI policy but delegated all AIMS responsibilities to the IT Director. The AI ethics committee, composed of external academics, meets quarterly but has no formal authority within the AIMS governance structure. Data scientists report to R&D project leads for technical work but to the Digital Transformation VP for AI governance matters. A recent internal audit found that no single individual is accountable for AI risk treatment decisions, as both divisions assume the other is responsible. The HR department reports that AI competence requirements have not been defined for any role involved in AI system development or operation.", questions: [
      { question: "The CEO endorsed the AI policy but delegated all AIMS responsibilities to the IT Director. Does this satisfy Clause 5.1 leadership requirements?", options: ["Yes, delegation of operational responsibilities is a standard management practice that demonstrates effective leadership", "No, while top management may delegate tasks, Clause 5.1 requires top management to retain accountability for AIMS effectiveness, including personal engagement in ensuring resources, communicating importance, and conducting management reviews", "Yes, provided the IT Director has sufficient authority and budget to implement the AIMS independently"], correct: 1, explanation: "Clause 5.1 requires top management to demonstrate leadership and commitment. While tasks can be delegated, accountability for AIMS effectiveness cannot be fully transferred. Top management must remain actively engaged." },
      { question: "The AI ethics committee has no formal authority within the AIMS governance structure. What is the most appropriate corrective action?", options: ["Dissolve the committee since informal advisory bodies create governance confusion", "Define the committee's role, responsibilities, and authority within the AIMS through Clause 5.3, establishing clear interfaces with decision-making processes such as risk treatment approval and impact assessment review", "Grant the committee veto power over all AI deployment decisions to ensure ethical oversight"], correct: 1, explanation: "Clause 5.3 requires defining organizational roles, responsibilities, and authorities. The ethics committee should have a defined role within the AIMS governance structure with clear interfaces to decision-making processes." },
      { question: "No single individual is accountable for AI risk treatment decisions due to the matrix structure. What AIMS requirement is violated?", options: ["Clause 6.1, which requires that risk assessment methodology be defined", "Clause 5.3, which requires that responsibilities and authorities for relevant roles are assigned and communicated, including clear accountability for AI risk treatment decisions", "Clause 9.2, which requires internal audit to verify risk treatment effectiveness"], correct: 1, explanation: "Clause 5.3 requires clear assignment and communication of roles, responsibilities, and authorities. Ambiguous accountability for risk treatment is a direct violation of this requirement." },
      { question: "AI competence requirements have not been defined for roles involved in AI development and operation. Which clauses are directly implicated?", options: ["Only Clause 7.2 (competence), which requires determining necessary competence for personnel whose work affects AI performance", "Clause 7.2 (competence) for defining required competence, Clause 7.1 (resources) for ensuring adequate human resources, and Clause 7.3 (awareness) for ensuring personnel understand their contribution to AIMS effectiveness", "Only Clause 5.3 (roles and responsibilities), since competence is implied by role definitions"], correct: 1, explanation: "Multiple support clauses are implicated: 7.2 requires determining and ensuring competence, 7.1 requires adequate resources including human capital, and 7.3 requires awareness of AI policy and individual contributions to AIMS effectiveness." },
      { question: "Data scientists report to different managers for technical work and AI governance. What risk does this dual-reporting structure create for AIMS effectiveness?", options: ["No risk, as matrix reporting structures are common and inherently effective for governance", "Risk that governance requirements are deprioritized when they conflict with project delivery timelines, and that accountability gaps emerge when neither reporting line takes ownership of AIMS compliance", "The only risk is increased administrative overhead, which can be addressed through process automation"], correct: 1, explanation: "Dual-reporting structures can create conflicts between delivery pressure and governance requirements. The AIMS must establish clear precedence rules and escalation paths to prevent AI governance from being subordinated to project pressures." }
    ]},

    // SCENARIO 5 – Performance evaluation and monitoring of AI systems (D5)
    { type: "scenario", scenario: "FinTrust Bank operates five AI systems: credit scoring, anti-money laundering (AML) detection, customer churn prediction, chatbot support, and algorithmic trading. The AIMS has been operational for fourteen months. The performance evaluation team has established KPIs for technical model accuracy but has not defined KPIs for AIMS process effectiveness. Internal audits have been scheduled annually, but the first audit has not yet been conducted. The management review was held six months ago but only discussed financial performance of AI projects, not AIMS effectiveness. The AML detection system's false-positive rate has increased by 40% over six months, but this trend was not identified because monitoring focuses only on monthly snapshots rather than trend analysis.", questions: [
      { question: "KPIs exist for model accuracy but not for AIMS process effectiveness. What does Clause 9.1 specifically require?", options: ["Only technical performance metrics for AI models, as these directly measure AI system effectiveness", "The organization must determine what needs to be monitored and measured, including AIMS process effectiveness and AI system performance, along with methods, timing, and responsibility for evaluation", "KPIs for process effectiveness are recommended but not required, as long as technical metrics demonstrate adequate AI performance"], correct: 1, explanation: "Clause 9.1 requires monitoring and measuring both the AIMS processes and AI system performance. Technical model metrics alone do not demonstrate that the management system itself is effective." },
      { question: "The first internal audit has not been conducted despite fourteen months of AIMS operation. What is the conformity status?", options: ["Conforming, because ISO/IEC 42001 does not specify a minimum audit frequency", "Non-conforming: while the standard does not mandate a specific frequency, fourteen months without an internal audit does not satisfy Clause 9.2's requirement to conduct audits at planned intervals, especially when the schedule specified annual audits", "Conforming, provided the audit is conducted before the external certification audit"], correct: 1, explanation: "Clause 9.2 requires internal audits at planned intervals. If the organization planned annual audits and fourteen months have passed without one, this is a nonconformity against both the standard and the organization's own audit program." },
      { question: "The management review discussed financial performance of AI projects but not AIMS effectiveness. What required inputs were missing?", options: ["Financial performance is a legitimate management review input and sufficient if AI projects are profitable", "Clause 9.3 requires management review inputs including audit results, AI system performance, nonconformities, monitoring results, and changes to external/internal issues relevant to the AIMS", "Management review inputs are at management's discretion as long as the review is documented"], correct: 1, explanation: "Clause 9.3 specifies required management review inputs including audit results, performance metrics, nonconformities, and changes to context. Financial performance alone does not satisfy these requirements." },
      { question: "The AML system's false-positive rate increased 40% over six months but was not detected because monitoring uses only monthly snapshots. What improvement is needed?", options: ["Monthly snapshots are sufficient; the 40% increase should have been visible in month-to-month comparisons", "The monitoring approach should include trend analysis and threshold-based alerting, enabling detection of gradual performance degradation such as model drift before it reaches critical levels", "The AML system should be retrained monthly to prevent any performance degradation"], correct: 1, explanation: "Trend analysis is essential for detecting gradual degradation like model drift. Monthly snapshots may show individual data points but miss patterns. Threshold-based alerting ensures timely response to emerging issues." },
      { question: "FinTrust's chatbot has no performance monitoring at all because it was classified as low-risk. Is this acceptable under the AIMS?", options: ["Yes, low-risk AI systems do not require performance monitoring under ISO/IEC 42001", "No, Clause 9.1 requires monitoring for all AI systems within scope; the depth and frequency may be proportionate to risk level, but complete absence of monitoring is non-conforming", "Yes, provided the chatbot's risk classification is documented and approved by management"], correct: 1, explanation: "All AI systems within the AIMS scope require some level of monitoring under Clause 9.1. Risk level informs the extent of monitoring but does not exempt a system from monitoring entirely." }
    ]},

    // SCENARIO 6 – Internal audit challenges in integrated systems (D5/D6)
    { type: "scenario", scenario: "GlobalInsure holds certifications for ISO 9001, ISO/IEC 27001, and ISO/IEC 42001. The internal audit manager has developed an integrated audit program covering all three standards. During the latest integrated audit cycle, the audit team discovers that the AI risk assessment references the information security risk assessment but does not include AI-specific risk criteria. The auditors also find that management review meetings for all three standards are combined, but the agenda template does not include AI-specific inputs required by ISO/IEC 42001 Clause 9.3. One auditor, who is highly experienced in ISO/IEC 27001 but has no AI background, audited the AI operational controls and reported no findings. A junior auditor identifies a potential nonconformity but is overruled by the lead auditor, who argues it is merely an observation.", questions: [
      { question: "The AI risk assessment references the information security risk assessment but lacks AI-specific risk criteria. What is the audit finding?", options: ["No finding, because integrating risk assessments is best practice for organizations with multiple management systems", "Nonconformity: while integration is appropriate, the AI risk assessment must include AI-specific risk criteria addressing concerns such as bias, transparency, data quality, and societal impact, which are distinct from information security risks", "Observation: the risk assessment is functional and can be enhanced at the next review cycle"], correct: 1, explanation: "Integration of risk assessments is acceptable, but ISO/IEC 42001 requires AI-specific risk criteria. An AI risk assessment that only references information security criteria fails to address the unique risks of AI systems." },
      { question: "Combined management reviews do not include AI-specific inputs. How should this be classified?", options: ["Observation: combining reviews is efficient and the AI topics can be added informally", "Nonconformity against Clause 9.3: combined management reviews must still address all required inputs for each standard, and missing AI-specific inputs means ISO/IEC 42001 requirements are not met", "No finding: management review content is at management's discretion"], correct: 1, explanation: "Clause 9.3 specifies mandatory management review inputs. Combined reviews must address all inputs from each applicable standard. Missing AI-specific inputs is a nonconformity regardless of the review format." },
      { question: "An auditor with ISO/IEC 27001 expertise but no AI background audited AI operational controls and found nothing. What concern does this raise?", options: ["No concern, since management system audit techniques are transferable across all standards", "The auditor may lack the competence to evaluate AI-specific operational controls effectively, potentially resulting in missed nonconformities; audit team competence must cover both management system and AI-specific knowledge", "This is only a concern if the auditor also lacks ISO 9001 experience"], correct: 1, explanation: "Effective auditing of AI operational controls requires understanding of AI-specific concepts. An auditor without AI knowledge may not recognize AI-specific nonconformities, undermining audit effectiveness." },
      { question: "A junior auditor's potential nonconformity finding is overruled by the lead auditor and classified as an observation. What principle is at stake?", options: ["The lead auditor has final authority and this is appropriate audit team management", "Audit findings must be based on objective evidence against audit criteria, not on the seniority of the auditor; the lead auditor should evaluate the evidence and justification rather than simply overruling based on judgment", "Junior auditors should not raise findings independently and should defer to the lead auditor's experience"], correct: 1, explanation: "Audit findings must be evidence-based. A lead auditor may evaluate the evidence differently, but simply overruling a finding without examining the evidence against audit criteria undermines audit objectivity and integrity." },
      { question: "GlobalInsure's integrated audit program must satisfy requirements across three standards. What is the most critical success factor?", options: ["Minimizing the total audit time across all three standards to reduce operational disruption", "Ensuring audit criteria, scope, and auditor competence address the specific requirements of each standard, particularly AI-specific requirements that do not exist in ISO 9001 or ISO/IEC 27001", "Using the same auditors for all three standards to maintain consistency in audit approach"], correct: 1, explanation: "Integrated audits must address each standard's unique requirements. AI-specific requirements in ISO/IEC 42001 require dedicated audit criteria and auditor competence that may not be covered by other standards." }
    ]},

    // SCENARIO 7 – Certification process complexities (D6)
    { type: "scenario", scenario: "MediScan AI has completed its AIMS implementation and applied for initial ISO/IEC 42001 certification. During Stage 1, the certification body auditor identifies that the documented AIMS scope excludes the organization's most critical AI system—a radiology diagnostic tool—citing the system's pending regulatory approval. The auditor also notes that the organization has defined AI objectives but cannot demonstrate how they were derived from the AI policy. Stage 2 is conducted eight months later. The audit team finds one major nonconformity (no evidence of AI system impact assessment for any deployed system) and three minor nonconformities. The organization submits a corrective action plan for the major nonconformity, proposing to complete impact assessments within nine months.", questions: [
      { question: "The AIMS scope excludes the radiology diagnostic tool because it is pending regulatory approval. Is this a valid basis for exclusion?", options: ["Yes, systems without regulatory approval should not be included in a management system scope until approved", "The pending approval status does not by itself justify exclusion; the scope should be based on Clause 4.3 criteria, and excluding the organization's most critical AI system may undermine the AIMS's relevance and credibility with interested parties", "Yes, because including unapproved systems would create certification liability for the certification body"], correct: 1, explanation: "Scope exclusions must be justified under Clause 4.3 criteria. Regulatory approval status is not a valid exclusion criterion. Excluding the most critical system raises questions about the AIMS's relevance and could be flagged as a concern during Stage 1." },
      { question: "AI objectives cannot be traced back to the AI policy. What Clause 6.2 requirement is unmet?", options: ["Clause 6.2 only requires objectives to be measurable, not traceable to policy", "Clause 6.2 requires AI objectives to be consistent with the AI policy; inability to demonstrate this linkage indicates the objectives may not reflect the organization's stated commitments", "Traceability between policy and objectives is a best practice but not a mandatory requirement"], correct: 1, explanation: "Clause 6.2 explicitly requires AI objectives to be consistent with the AI policy. If the organization cannot demonstrate how objectives derive from policy commitments, this consistency requirement is not met." },
      { question: "Stage 2 is conducted eight months after Stage 1. Is this timing appropriate under ISO/IEC 17021-1?", options: ["Yes, there is no time limit between Stage 1 and Stage 2", "Potentially problematic: ISO/IEC 17021-1 requires that Stage 2 be conducted within a timeframe that allows Stage 1 findings to be addressed but not so long that conditions may have significantly changed, typically within six months", "No, Stage 2 must occur within 30 days of Stage 1"], correct: 1, explanation: "While there is no rigid deadline, certification body practice based on ISO/IEC 17021-1 typically expects Stage 2 within six months of Stage 1. Eight months may require reassessment of Stage 1 conclusions." },
      { question: "The organization proposes completing impact assessments for the major nonconformity within nine months. What is the certification body's likely response?", options: ["Accept the nine-month timeline since complex impact assessments require significant effort", "Require resolution within six months, as ISO/IEC 17021-1 indicates that if a major nonconformity cannot be resolved within six months after Stage 2, a partial or full Stage 2 re-audit should be conducted", "Reject the corrective action plan and immediately deny certification"], correct: 1, explanation: "ISO/IEC 17021-1 provides that if major nonconformity corrections cannot be verified within six months, a re-audit is typically required. A nine-month proposal would likely trigger this provision." },
      { question: "Three minor nonconformities were also identified. What is their impact on the certification decision?", options: ["Minor nonconformities have no impact on the certification decision", "Minor nonconformities require corrective action plans to be submitted and accepted by the certification body; the certification decision considers whether these corrective actions are adequate and will be implemented", "Minor nonconformities automatically escalate to a major nonconformity if there are three or more"], correct: 1, explanation: "Minor nonconformities require corrective action plans. The certification body evaluates these plans as part of the certification decision. They do not automatically escalate based on quantity." }
    ]},

    // SCENARIO 8 – Data governance and AI lifecycle (D4)
    { type: "scenario", scenario: "DataMed operates an AI-powered clinical decision support system trained on electronic health records from partnering hospitals. The data pipeline involves receiving de-identified patient data from twelve hospitals, performing data cleaning and feature engineering, training ensemble models, and deploying to a cloud environment. A data quality audit reveals that three hospitals have been sending records with a systematic coding error that affects 15% of diagnoses. The data engineering team fixed the error in the pipeline but did not retrain existing models. Additionally, the organization has no documented data lineage tracking, and the data retention policy was inherited from a general IT policy that does not account for AI training data lifecycle requirements.", questions: [
      { question: "Three hospitals sent records with systematic coding errors affecting 15% of diagnoses. The pipeline was fixed but models were not retrained. What is the AIMS concern?", options: ["No concern, since the pipeline fix prevents future errors and existing models will naturally improve over time through ongoing learning", "Models trained on corrupted data may produce biased or inaccurate outputs; the organization must assess the impact on existing models, determine whether retraining is necessary, and implement controls to prevent similar data quality issues", "The concern is limited to a data quality documentation issue that should be noted in the data management records"], correct: 1, explanation: "Corrupted training data affects model integrity. Under AI operational controls and data governance requirements, the organization must assess impact on deployed models and determine appropriate remediation, not just fix the pipeline." },
      { question: "The organization has no documented data lineage tracking. Which AIMS requirements does this affect?", options: ["Only Clause 7.5 documented information, as data lineage is a documentation practice", "Multiple requirements including data governance controls for traceability, AI risk assessment capability for identifying data-related risks, and the ability to conduct effective root cause analysis for AI system issues", "Data lineage tracking is a best practice but not required under ISO/IEC 42001"], correct: 1, explanation: "Data lineage tracking supports multiple AIMS requirements: data governance controls require traceability of data used in AI systems, risk assessment needs visibility into data sources, and incident investigation requires understanding data provenance." },
      { question: "The data retention policy was inherited from a general IT policy. What is inadequate about this approach?", options: ["General IT retention policies are sufficient since all data is subject to the same retention requirements", "AI training data has unique lifecycle requirements including considerations for model retraining, bias testing, regulatory obligations for AI transparency, and the need to maintain data for model validation and audit purposes", "The data retention policy only needs updating if the organization processes personally identifiable information"], correct: 1, explanation: "AI training data has lifecycle requirements distinct from general IT data, including needs for model retraining, bias verification, regulatory compliance, and audit trail maintenance. A general IT policy does not address these considerations." },
      { question: "DataMed receives de-identified patient data from twelve hospitals. What third-party data governance control is most important?", options: ["Requiring all hospitals to obtain ISO/IEC 42001 certification before providing data", "Establishing data quality agreements with each hospital specifying data standards, error reporting requirements, and responsibilities for data accuracy, along with regular data quality assessments", "Conducting annual on-site audits of each hospital's electronic health record system"], correct: 1, explanation: "Data quality agreements establish shared expectations and responsibilities. Regular quality assessments ensure ongoing compliance. This is more practical and effective than requiring certification or conducting physical audits of all data sources." },
      { question: "The ensemble model combines outputs from multiple sub-models. What AI lifecycle challenge does this create for the AIMS?", options: ["No additional challenge, as ensemble models are standard ML practice", "Ensemble models create challenges for explainability, version control, and change management, as each sub-model may require independent monitoring, and interactions between sub-models must be tracked throughout the lifecycle", "The only challenge is computational cost, which affects resource planning under Clause 7.1"], correct: 1, explanation: "Ensemble models add complexity to lifecycle management: each sub-model has its own training data, performance characteristics, and drift patterns. The AIMS must address explainability challenges, coordinate version control, and monitor interactions between components." }
    ]},

    // SCENARIO 9 – Continual improvement and corrective action (D6/D5)
    { type: "scenario", scenario: "LogiAI provides AI-powered logistics optimization for global shipping companies. After two years of AIMS operation, the management review reveals several patterns: corrective actions from internal audits are consistently closed on time but the same types of nonconformities recur; the AI risk register has not been substantially updated since initial implementation despite significant changes in AI technology and business operations; customer complaints about route optimization errors have increased 25% year-over-year; and the organization's AI competence development program has delivered training to only 30% of personnel in AI-related roles. The continual improvement process consists solely of tracking corrective action closure rates.", questions: [
      { question: "The same types of nonconformities recur despite corrective actions being closed on time. What does this indicate about the corrective action process?", options: ["The corrective actions are effective but the nonconformities are inherently unavoidable in AI operations", "The corrective actions are likely addressing symptoms rather than root causes; Clause 10.1 requires determining the cause of nonconformities and taking action to ensure they do not recur or occur elsewhere", "Recurring nonconformities are acceptable as long as each instance is documented and closed"], correct: 1, explanation: "Clause 10.1 requires root cause analysis and action to prevent recurrence. Recurring nonconformities indicate that corrective actions are addressing symptoms rather than underlying causes, representing a systemic failure in the corrective action process." },
      { question: "The AI risk register has not been substantially updated in two years. What clause is most directly violated?", options: ["Clause 10.2 continual improvement, since failing to update the risk register prevents improvement", "Clause 6.1 and Clause 8.2: the risk assessment must be updated when significant changes occur, and the organization must perform AI risk assessments at planned intervals or when changes are proposed or occur", "Clause 9.3 management review, since the risk register should be a standing agenda item"], correct: 1, explanation: "Clause 6.1 requires planning to address risks, and Clause 8.2 requires AI risk assessment at planned intervals or when significant changes occur. A stagnant risk register in a rapidly evolving AI landscape indicates non-conformity with both clauses." },
      { question: "Customer complaints about route optimization errors increased 25%. How should this be handled within the AIMS?", options: ["As a commercial performance issue managed outside the AIMS, since customer satisfaction is a business metric", "Through Clause 9.1 monitoring as an indicator of AI system performance degradation, feeding into the risk assessment process and potentially triggering corrective action under Clause 10.1", "By immediately retraining the route optimization model before investigating the root cause"], correct: 1, explanation: "Increased customer complaints are a performance indicator that should trigger investigation through the AIMS. The monitoring process should detect trends, the risk assessment should evaluate implications, and corrective action should address root causes." },
      { question: "Only 30% of personnel in AI-related roles have received competence training. What is the conformity status?", options: ["Conforming, because the organization has a training program in place even if not fully executed", "Non-conforming with Clause 7.2: the organization must ensure that persons doing work affecting AI system performance have the necessary competence, and 70% of untrained personnel represents a significant gap", "Conforming, provided the remaining 70% have prior AI experience from previous employment"], correct: 1, explanation: "Clause 7.2 requires the organization to determine necessary competence and ensure personnel have it. Having a program that reaches only 30% of relevant personnel does not satisfy this requirement, regardless of the program's existence." },
      { question: "Continual improvement is limited to tracking corrective action closure rates. Why is this insufficient under Clause 10.2?", options: ["Corrective action closure rates are the primary metric for continual improvement", "Clause 10.2 requires improving the suitability, adequacy, and effectiveness of the AIMS; this includes proactive improvements based on monitoring trends, technology changes, best practices, and management review outputs, not merely reactive closure of findings", "Tracking closure rates is sufficient if the rate exceeds 95%"], correct: 1, explanation: "Clause 10.2 requires continual improvement of the AIMS as a whole. This encompasses proactive improvements driven by analysis, trends, and opportunities, not just reactive closure of identified nonconformities." }
    ]},

    // SCENARIO 10 – Generative AI risk and emerging technology (D1/D4)
    { type: "scenario", scenario: "CreativeAI is a marketing agency that recently adopted a large language model (LLM) to generate advertising copy, social media posts, and client communications. The LLM is accessed via API from a third-party provider who updates the model periodically without prior notice. Staff members have begun using the LLM to draft contract language and legal disclaimers without legal review. The organization discovered that the LLM occasionally generates content that closely resembles copyrighted material from competitors. There is no documented acceptable-use policy for generative AI tools. The data protection officer raises concerns that staff are pasting client confidential information into the LLM prompts, potentially exposing it to the third-party provider.", questions: [
      { question: "Staff use the LLM to draft contract language without legal review. What AIMS control gap does this represent?", options: ["A Clause 7.3 awareness gap, as staff are unaware of AI limitations", "A gap in operational controls (Clause 8.1) for defining acceptable use boundaries, human oversight requirements, and approval workflows for AI-generated outputs in high-stakes contexts", "A Clause 5.2 policy gap only, since the AI policy should prohibit all use of generative AI for legal content"], correct: 1, explanation: "Clause 8.1 requires operational planning and control with established criteria. Using AI for high-stakes outputs like legal documents without defined oversight and approval processes represents a control gap, not merely an awareness or policy issue." },
      { question: "The LLM generates content resembling copyrighted material. What AIMS requirement is most relevant?", options: ["Clause 7.5 documented information, requiring documentation of all generated content", "AI risk assessment (Clause 8.2) should identify intellectual property infringement as a risk, with risk treatment including output review processes, content verification controls, and contractual protections with the LLM provider", "Clause 9.1 monitoring, requiring automated plagiarism detection for all outputs"], correct: 1, explanation: "Intellectual property infringement is an AI-specific risk that should be identified through risk assessment and addressed through appropriate treatment measures, including both technical controls and contractual arrangements." },
      { question: "The LLM provider updates the model without prior notice. What AIMS challenge does this create?", options: ["No challenge, as the provider is responsible for model quality and the organization benefits from continuous improvement", "The organization cannot maintain effective change management, impact assessment, or performance monitoring when the underlying model changes unpredictably, potentially altering outputs, introducing new risks, or affecting compliance", "The only challenge is contractual, requiring renegotiation of service level agreements"], correct: 1, explanation: "Unannounced model updates undermine the organization's ability to manage changes, assess impacts, and maintain consistent performance monitoring. This affects multiple AIMS requirements including operational control and risk management." },
      { question: "Staff paste client confidential information into LLM prompts. Which combination of AIMS and related controls is most relevant?", options: ["Only ISO/IEC 27001 information security controls, as this is a data protection issue outside ISO/IEC 42001 scope", "Annex A controls on data governance and data quality management, operational controls (Clause 8.1) for AI system use, and the interface with information security management for protecting confidential information in AI contexts", "Only Clause 7.3 awareness, requiring a reminder about data confidentiality"], correct: 1, explanation: "This issue spans multiple control areas: AI data governance controls address data handling in AI contexts, operational controls define acceptable use, and the AIMS must interface with information security management. It is not solely an awareness or information security issue." },
      { question: "There is no acceptable-use policy for generative AI tools. What is the most comprehensive AIMS-aligned action?", options: ["Add a single sentence to the existing AI policy stating that generative AI must be used responsibly", "Develop operational procedures (Clause 8.1) defining acceptable use cases, prohibited uses, data handling requirements, output review processes, and human oversight requirements for generative AI, integrated with the overall AI policy and risk treatment framework", "Ban all use of generative AI tools until a comprehensive policy can be developed"], correct: 1, explanation: "Acceptable-use procedures should be developed as part of operational controls, addressing specific use cases, restrictions, and oversight requirements. This provides practical guidance beyond a generic policy statement and is more proportionate than a blanket ban." }
    ]},

    // STANDALONE QUESTIONS (30 questions)
    { type: "standalone", questions: [
      // Domain 1 – Fundamentals (7 more to reach 17 total with scenarios)
      { question: "ISO/IEC 22989 defines several types of machine learning. Which type uses a reward signal to optimize an agent's behavior through interaction with an environment?", options: ["Supervised learning, where the reward signal serves as the label", "Reinforcement learning, where the agent learns to maximize cumulative reward through trial-and-error interaction", "Self-supervised learning, where the model generates its own reward signals from unlabeled data"], correct: 1, explanation: "Reinforcement learning is specifically defined by the agent-environment interaction paradigm where the agent learns through reward signals, distinguishing it from supervised (labeled data) and self-supervised (self-generated labels) approaches." },
      { question: "Under the EU AI Act, which practice is explicitly prohibited as posing unacceptable risk?", options: ["AI systems that generate synthetic media content without watermarking", "Real-time remote biometric identification systems in publicly accessible spaces by law enforcement, subject to narrow exceptions", "AI systems used for automated insurance claim assessment without human review"], correct: 1, explanation: "Real-time remote biometric identification in public spaces by law enforcement is classified as unacceptable risk with very narrow exceptions, distinguishing it from limited-risk transparency obligations and high-risk requirements." },
      { question: "The NIST AI RMF 'Map' function focuses on which activities?", options: ["Mapping organizational processes to AI governance requirements and creating process flow diagrams", "Establishing context, identifying AI risks, and understanding the AI system's impacts across its lifecycle, including stakeholder identification", "Mapping AI models to specific hardware configurations for deployment optimization"], correct: 1, explanation: "The Map function in NIST AI RMF is about understanding context, identifying and framing AI risks, and recognizing impacts, not about process mapping or technical deployment." },
      { question: "ISO/IEC 38507 addresses AI governance at the governing body level. What distinguishes governance from management in this context?", options: ["Governance and management are synonymous terms used interchangeably in ISO/IEC 38507", "Governance involves evaluating, directing, and monitoring AI use at the strategic level, while management involves planning, building, running, and monitoring AI systems at the operational level", "Governance applies only to publicly listed companies, while management applies to all organizations"], correct: 1, explanation: "ISO/IEC 38507 distinguishes governing body responsibilities (evaluate, direct, monitor) from management activities (plan, build, run, monitor), establishing different accountability levels for AI oversight." },
      { question: "According to ISO/IEC TR 24028, which category of threats to AI trustworthiness includes adversarial attacks designed to manipulate AI system inputs?", options: ["Threats from data quality issues such as incomplete or biased training datasets", "Threats from intentional adversarial manipulation, including evasion attacks, data poisoning, and model extraction", "Threats from system reliability issues such as hardware failures and software bugs"], correct: 1, explanation: "ISO/IEC TR 24028 identifies intentional adversarial threats as a distinct category that includes various attack vectors designed to manipulate AI behavior, separate from data quality and reliability concerns." },
      { question: "What is the primary purpose of ISO/IEC 42006 in the AI standards ecosystem?", options: ["To provide requirements for organizations implementing an AIMS", "To specify requirements for bodies providing audit and certification of AI management systems, ensuring consistent and competent AIMS certification globally", "To establish a framework for assessing AI system impacts on society"], correct: 1, explanation: "ISO/IEC 42006 specifically addresses certification body requirements, ensuring that organizations auditing AIMS have the necessary competence and processes, complementing ISO/IEC 42001 which addresses the AIMS itself." },
      { question: "An AI system uses transfer learning, applying knowledge from a pre-trained model to a new domain. Under ISO/IEC 22989, what classification consideration is most relevant?", options: ["Transfer learning automatically classifies the system as general AI since it applies across domains", "The classification depends on the specific learning techniques used in both the pre-training and fine-tuning phases, and the system remains narrow AI focused on specific tasks", "Transfer learning systems are not covered by ISO/IEC 22989 as they represent a hybrid approach"], correct: 1, explanation: "Transfer learning uses knowledge from one domain in another but remains within the narrow AI category. ISO/IEC 22989's classification framework considers the learning approach while recognizing that transfer learning does not constitute general AI." },

      // Domain 2 – AIMS requirements (5 questions)
      { question: "The Harmonized Structure (Annex SL) provides common clauses across management system standards. Which clause is unique to ISO/IEC 42001 and does not have a direct equivalent in ISO 9001 or ISO/IEC 27001?", options: ["Clause 4.1 Understanding the organization and its context", "The requirement for AI-specific risk assessment and AI system impact assessment within Clause 8, along with the Annex A control framework for AI", "Clause 10.1 Nonconformity and corrective action"], correct: 1, explanation: "While the high-level structure is shared, ISO/IEC 42001 introduces AI-specific requirements in Clause 8 for AI risk assessment and impact assessment, plus a unique Annex A control framework. Clauses 4.1 and 10.1 have equivalents in other standards." },
      { question: "ISO/IEC 42001 contains four informative annexes (A through D). What is the relationship between Annex A and Annex B?", options: ["Annex A contains the control objectives and controls; Annex B provides implementation guidance for the controls listed in Annex A", "Annex A contains mandatory requirements; Annex B contains optional recommendations", "Annex A applies to AI developers; Annex B applies to AI users"], correct: 0, explanation: "Annex A establishes control objectives and controls, while Annex B provides detailed implementation guidance for those controls. They work as a pair, with B explaining how to implement what A specifies." },
      { question: "How does ISO/IEC 42001 Clause 8 differ from the typical Clause 8 in other Harmonized Structure standards?", options: ["It contains identical operational requirements to ISO/IEC 27001 Clause 8", "It introduces AI-specific operational requirements including AI risk assessment, AI risk treatment, and AI system impact assessment, which go beyond the generic operational planning found in other standards", "It removes the requirement for operational planning and replaces it with AI lifecycle management"], correct: 1, explanation: "While the Harmonized Structure provides a common Clause 8 framework, ISO/IEC 42001 adds AI-specific sub-clauses (8.2 AI risk assessment, 8.3 AI risk treatment, 8.4 AI system impact assessment) that are unique to this standard." },
      { question: "Which ISO/IEC 42001 annex provides guidance on AI-related organizational objectives and potential sources of risk?", options: ["Annex A, which lists control objectives", "Annex C, which provides guidance on AI-related organizational objectives, and Annex D, which provides potential sources of AI-related risk", "Annex B, which covers implementation guidance for all aspects including objectives and risk"], correct: 1, explanation: "Annex C specifically addresses organizational objectives related to AI, while Annex D catalogs potential sources of AI-related risk. These informative annexes complement the normative requirements in the main body." },
      { question: "An organization is implementing ISO/IEC 42001 and questions whether it must implement every control in Annex A. What is the correct interpretation?", options: ["All Annex A controls are mandatory and must be implemented", "The organization determines which controls are applicable through its risk assessment and documents inclusions and exclusions with justification in the Statement of Applicability", "Annex A controls are entirely optional and serve only as suggestions"], correct: 1, explanation: "Annex A controls are reference controls. The organization selects applicable controls based on risk assessment results and documents decisions in the SoA, including justification for any exclusions." },

      // Domain 3 – Planning (5 more to reach 20 with scenarios)
      { question: "An organization's context analysis identifies that a key competitor has suffered reputational damage from AI bias incidents. How should this be treated under Clause 4.1?", options: ["As an opportunity only, since the competitor's failure benefits the organization's market position", "As an external issue that represents both a risk (similar incidents could occur internally) and an opportunity (to differentiate through responsible AI practices), informing the risk assessment and AI objectives", "As irrelevant external information, since competitor activities do not affect the organization's AIMS"], correct: 1, explanation: "Clause 4.1 requires identifying external issues relevant to the organization's purpose. A competitor's AI-related incident is relevant as both a risk indicator and an opportunity, informing the organization's own risk assessment and strategic direction." },
      { question: "When planning changes to the AIMS under Clause 6.3, an organization proposes migrating all AI workloads to a new cloud provider. What must be considered?", options: ["Only the cost differential between cloud providers and the migration timeline", "The purpose of the change, potential consequences for AIMS integrity, availability of resources, and allocation of responsibilities, including impacts on data governance, third-party risk, and AI system continuity", "Only whether the new cloud provider holds ISO/IEC 27001 certification"], correct: 1, explanation: "Clause 6.3 requires considering the purpose of changes, potential consequences, AIMS integrity, resource availability, and responsibility allocation. A cloud migration affects multiple AIMS areas including data governance and third-party management." },
      { question: "An organization sets an AI objective to 'improve AI fairness.' Why might an auditor flag this as non-conforming with Clause 6.2?", options: ["Fairness is not a valid topic for AI objectives under ISO/IEC 42001", "The objective lacks specificity: Clause 6.2 requires AI objectives to be measurable where practicable, and 'improve AI fairness' does not define what will be measured, by how much, for which systems, or by when", "AI objectives related to ethical principles like fairness must be approved by the ethics committee before they can be set"], correct: 1, explanation: "Clause 6.2 requires objectives to be measurable where practicable. A vague objective like 'improve AI fairness' does not specify metrics, targets, scope, or timelines, making it impossible to evaluate achievement." },
      { question: "During risk assessment, two AI systems are identified with similar technical risk profiles but different affected populations—one serves enterprise clients and the other serves vulnerable individuals. How should this affect risk evaluation?", options: ["Technical risk profiles are the sole determinant of risk level, so both systems should receive identical risk ratings", "The risk evaluation should consider the nature and vulnerability of affected populations as a factor, potentially resulting in different risk levels despite similar technical profiles, as societal impact differs", "The system serving vulnerable individuals should be excluded from the AIMS scope to reduce organizational risk exposure"], correct: 1, explanation: "AI risk assessment should consider not only technical risk but also the potential impact on affected parties. Systems affecting vulnerable populations carry higher societal risk and may require more stringent controls, even with similar technical risk profiles." },
      { question: "An organization's AI policy states commitment to 'transparency in all AI operations.' During implementation, the team discovers that full transparency would compromise proprietary algorithms. How should this tension be resolved?", options: ["Revise the AI policy to remove the transparency commitment entirely", "Maintain the transparency commitment but define appropriate levels of transparency through risk treatment, distinguishing between transparency to affected parties about AI use and decisions versus disclosure of proprietary technical details", "Implement full transparency regardless of proprietary concerns, as the AI policy commitment is binding"], correct: 1, explanation: "Transparency can be implemented at different levels. The AI policy commitment should be operationalized through risk treatment that balances transparency obligations to affected parties with legitimate protection of proprietary information." },

      // Domain 4 – Implementation (3 more to reach 18 with scenarios)
      { question: "An organization maintains AIMS documented information exclusively in a cloud-based collaboration platform. What Clause 7.5 consideration is most important?", options: ["Cloud-based documentation is not permitted under ISO/IEC 42001; documented information must be maintained on local servers", "The organization must ensure appropriate controls for availability, access, integrity, and protection of documented information, including backup, version control, and access management regardless of the storage medium", "Cloud storage is acceptable only if the cloud provider holds ISO/IEC 27001 certification"], correct: 1, explanation: "Clause 7.5 requires controls for documented information regardless of storage format. Cloud-based systems must satisfy requirements for availability, access control, integrity, and protection just as any other storage medium would." },
      { question: "An AI system operates autonomously in production with no human-in-the-loop capability. What Annex A control consideration is most relevant?", options: ["This automatically violates ISO/IEC 42001 since all AI systems must have human oversight", "The organization must evaluate whether the level of autonomy is appropriate given the system's risk profile, establish monitoring controls, and define intervention mechanisms proportionate to the potential impact of autonomous decisions", "Autonomous AI systems require only enhanced logging controls to maintain an audit trail"], correct: 1, explanation: "ISO/IEC 42001 does not prohibit autonomous AI systems but requires that the level of autonomy be appropriate to the risk. Controls must be proportionate, including monitoring and intervention mechanisms based on the system's risk profile and impact." },
      { question: "An organization's AI competence program focuses exclusively on technical ML skills for data scientists. What aspect of Clause 7.2 is being overlooked?", options: ["Technical ML skills are the only competence required under Clause 7.2 for AI-related personnel", "Clause 7.2 requires competence for all persons whose work affects AI system performance, including non-technical roles such as product managers, business analysts, and operational staff who need understanding of AI ethics, governance, and organizational AI policy", "Clause 7.2 only applies to personnel who directly develop AI models, not to supporting roles"], correct: 1, explanation: "Clause 7.2 requires ensuring competence for all personnel whose work affects AI performance. This extends beyond data scientists to include anyone involved in AI system decisions, operations, or governance, requiring broader competence in AI ethics and governance." },

      // Domain 5 – Monitoring (3 more to reach 10 with scenarios)
      { question: "During management review, top management requests that AI performance reports focus only on positive metrics and exclude incidents. What should the AIMS manager do?", options: ["Comply with top management's request since they determine management review content", "Explain that Clause 9.3 requires management review to consider specific inputs including nonconformities and corrective actions, and that omitting negative information would result in non-conformity and undermine AIMS effectiveness", "Present only positive metrics in the formal review but provide incident information informally outside the meeting"], correct: 1, explanation: "Clause 9.3 specifies mandatory management review inputs including nonconformities and corrective actions. The AIMS manager should ensure top management understands these requirements cannot be selectively applied." },
      { question: "An organization monitors individual AI model performance but does not assess overall AIMS effectiveness. What is missing from their Clause 9.1 implementation?", options: ["Nothing is missing; AI model performance is the primary indicator of AIMS effectiveness", "The organization needs to evaluate the effectiveness of the AIMS as a management system, including process effectiveness, control adequacy, risk treatment outcomes, and progress toward AI objectives, not solely individual model metrics", "Overall AIMS effectiveness can only be assessed during external audits, not through internal monitoring"], correct: 1, explanation: "Clause 9.1 requires monitoring both AI system performance and AIMS process effectiveness. Individual model metrics indicate technical performance but do not demonstrate whether the management system's processes, controls, and risk treatments are working effectively." },
      { question: "Internal audit findings from the previous cycle identified three minor nonconformities. At the current management review, the AIMS manager reports that all three have been closed. What additional information should be provided?", options: ["No additional information is needed once corrective actions are verified as closed", "Evidence that the corrective actions were effective in preventing recurrence, trends in nonconformity types, and whether additional systemic improvements are indicated", "Only the dates of closure and the names of responsible individuals"], correct: 1, explanation: "Management review should assess not just closure but effectiveness of corrective actions, patterns in findings, and systemic improvement needs. Simply reporting closure does not demonstrate that the underlying issues have been resolved." },

      // Domain 6 – Improvement & certification (2 more to reach 10 with scenarios)
      { question: "During a surveillance audit, the auditor discovers that the organization has significantly expanded its AI operations but not updated the certified AIMS scope. What action should the certification body consider?", options: ["No action required during surveillance; scope changes are only evaluated at recertification", "Evaluate whether the scope change is significant enough to require a special audit or scope extension audit, as the current certificate may not accurately represent the organization's AIMS", "Automatically expand the certified scope to include the new AI operations"], correct: 1, explanation: "Significant changes to an organization's operations may affect the validity of the certification scope. The certification body should evaluate whether additional audit activities are needed to verify the AIMS covers the expanded operations." },
      { question: "An organization achieves ISO/IEC 42001 certification and then makes no changes to its AIMS for three years, arguing that stability demonstrates maturity. What AIMS requirement does this potentially violate?", options: ["No requirement is violated; a stable, unchanging AIMS demonstrates maturity and effectiveness", "Clause 10.2 requires continual improvement of AIMS suitability, adequacy, and effectiveness; a completely static system in a rapidly evolving AI landscape suggests the organization is not adapting to changes in technology, risks, or best practices", "Only Clause 6.3 is violated, since the organization did not plan any changes"], correct: 1, explanation: "Clause 10.2 mandates continual improvement. The AI field evolves rapidly, and a completely static AIMS is unlikely to remain suitable and effective over three years. Stability without improvement indicates stagnation rather than maturity." },

      // Additional questions for domain balance
      { question: "An organization identifies that its AI system's training pipeline uses open-source libraries with known vulnerabilities. Under which AIMS consideration should this be addressed?", options: ["Only under ISO/IEC 27001 information security controls, as software vulnerabilities are an IT concern", "As part of the AI risk assessment process, since vulnerable components in the AI pipeline can compromise model integrity, data quality, and system reliability, affecting the AI system's trustworthiness", "As a procurement issue outside the AIMS scope, to be addressed through vendor management"], correct: 1, explanation: "Vulnerabilities in AI pipeline components affect AI system integrity and trustworthiness. While overlapping with information security, this is also an AI-specific risk that should be identified and treated within the AIMS risk assessment." },
      { question: "A certification body discovers during Stage 2 that the organization implemented additional Annex A controls beyond those listed in its SoA. Is this a nonconformity?", options: ["Yes, all implemented controls must be listed in the SoA, and unlisted controls indicate scope creep", "Not inherently a nonconformity in terms of control implementation, but the SoA should accurately reflect the organization's control decisions; the SoA should be updated to include all implemented controls with their justification", "No, implementing extra controls beyond the SoA demonstrates a commitment to exceeding minimum requirements"], correct: 1, explanation: "The SoA should be an accurate reflection of the organization's control decisions. While implementing additional controls is positive, the SoA must be updated to maintain its integrity as a documented reference of control applicability." },
      { question: "An organization's Clause 7.4 communication plan addresses internal communication about the AIMS but does not include external communication procedures. Is this sufficient?", options: ["Yes, AIMS communication is primarily an internal matter", "No, Clause 7.4 requires the organization to determine both internal and external communications relevant to the AIMS, including what, when, with whom, and how to communicate", "External communication is only required when the organization receives complaints or inquiries"], correct: 1, explanation: "Clause 7.4 explicitly requires determining internal and external communication needs. External communication may include communicating with regulators, customers, and other interested parties about AI governance matters." },
      { question: "During an AI system impact assessment under Clause 8.4, an organization evaluates only the direct technical impacts of the AI system. What broader impacts should be assessed?", options: ["Technical impacts are the only impacts within ISO/IEC 42001 scope", "Broader impacts including effects on individuals and groups (such as fairness, privacy, and autonomy), societal impacts, economic impacts, and environmental impacts, consistent with ISO/IEC 42005 guidance", "Only impacts that directly generate financial liability for the organization"], correct: 1, explanation: "AI system impact assessment should consider a broad range of impacts on individuals, groups, and society, not just direct technical effects. ISO/IEC 42005 provides guidance on the scope of impact assessment beyond narrow technical considerations." },
      { question: "An organization plans to use synthetic data to augment its training dataset. What AIMS consideration is most important?", options: ["Synthetic data eliminates all data governance concerns since no real personal data is involved", "The organization must assess the quality and representativeness of synthetic data, evaluate whether it introduces biases or artifacts that could affect model performance, and document the synthetic data generation process within its data governance framework", "Synthetic data is not recognized under ISO/IEC 42001 and cannot be used for AI training within a certified AIMS"], correct: 1, explanation: "Synthetic data has its own quality and governance considerations. It may introduce biases or artifacts that affect model performance. The AIMS data governance framework must address synthetic data generation, quality assessment, and documentation." }
    ]}
  ]
};
